-- چک‌لیست هر تجهیز (با ارجاع به equipment بر اساس code)
do $$
declare
  eq_id uuid;
begin
  select id into eq_id from equipment where code = '1';
بررسی چشمی اینکه آیا موتورهای ویبره با هم هم‌گام هستند یا یکی از آن‌ها صدای متفاوت یا لرزش نامنظم دارد');
موتورهای ویبره با شدت زیاد به بدنه هاپر ضربه می‌زنند. بررسی کنید که پیچ‌های نگهدارنده موتور ویبره شل نشده باشند (این پیچ‌ها باید حتماً با واشر فنری یا مهره قفل‌کننده  بسته شده باشند');
اگر موتورهای ویبره روی فنر یا پد لاستیکی سوار شده‌اند، بررسی کنید که پدها پاره نشده باشند یا فنرها دچار تغییر شکل نشوند.');
 شنیدن صدای برخورد فلز به فلز  که نشان‌دهنده شل شدن یکی از اتصالات موتور به بدنه هاپر است.');
موتورهای ویبره معمولاً گرم‌تر از موتورهای معمولی هستند، اما داغ شدن بیش از حد نشانه خرابی رولور  یا گیر کردن ذرات داخل آن است.');
بررسی چشمی اینکه آیا موتورهای ویبره با هم هم‌گام هستند یا یکی از آن‌ها صدای متفاوت یا لرزش نامنظم دارد');
 شنیدن صدای برخورد فلز به فلز  که نشان‌دهنده شل شدن یکی از اتصالات موتور به بدنه هاپر است.');
بررسی چشمی اینکه آیا موتورهای ویبره با هم هم‌گام هستند یا یکی از آن‌ها صدای متفاوت یا لرزش نامنظم دارد');
