  select id into eq_id from equipment where code = '3';
 برای شناسایی افت کارایی یا نیم‌سوز شدن(آمپر هر سه فاز را کنترل کنید اختلاف زیاد بین فازها یا آمپر بالاتر از نرمال یعنی بار اضافی، مشکل در سیم پیچ گیرمکانیکی و ضعف برق ورودی)');
 گل و لای، رطوبت ، ترک در بدنه و شکستگی فن');
بررسی اینکه آیا فنرها هنوز حالت استاندارد خود را دارند یا به دلیل بار بیش از حد، “کنده” یا “خمیده” شده‌اند.');
بررسی دقیق ۸ عدد فنر برای یافتن هرگونه ترک یا شکستگی در بدنه فنر');
 اگر یکی از فنرها بیش از بقیه فشرده شده باشد، یعنی بار روی گریزلی نامتقارن است (مثلاً مواد یک سمت گریزلی بیشتر از سمت دیگر می‌ریزد). این موضوع باعث لرزش غیرعادی و آسیب به شفت می‌شود.');
بررسی اینکه پیچ‌هایی که فنر را به شاسی یا به صفحه گریزلی متصل می‌کنند، بر اثر لرزش شل نشده باشند.-
نشانه خطر: اگر پیچ‌ها شل باشند، فنر شروع به “ضربه‌زدن”  می‌کند که صدای بسیار آزاردهنده‌ای دارد و می‌تواند باعث شکستن پایه گریزلی شود.)');
اگر فنرها درست نباشند، لرزش گریزلی به موتور گیربکس منتقل شده و باعث خرابی بلبرینگ‌های موتور می‌شود.');
چک کردن دمای گیربکس (همان‌طور که قبلاً گفته شد) برای اطمینان از اینکه لرزش‌های ناشی از خرابی فنرها به گیربکس آسیب نزده است.');
  select id into eq_id from equipment where code = '4';
ترومل باید نرم و یکنواخت بچرخد، صدای غیرعادی مثل تق تق ، کوبش ، سایش فلز و لرزش ضربه ای باید فورا بررسی شود زیرا می تواند خرابی رولر یا تکیه گاه باشد یا کج شدن بدنه و یا  گیر کردن سنگ یا توده مواد داخل استوانه باشد');
اطمینان از گرفتگی نداشتن سوراخ‌ها برای شستشوی بهینه');
اطمینان از روغن‌کاری کافی اگر زنجیر خشک، شل یا ضربه‌زننده باشد، هم عمر زنجیر کم می‌شود هم به گیربکس فشار می‌آید');
دما ، صدا، لقی غیر عادی و روغن ریزی و گریس ریزی');
بررسی ظاهری برای اطمینان از اینکه پوشش تفلون نشده یا کنده شده باشد، اگر تفلون پوشش‌دهی خود را از دست بدهد و زنجیر مستقیماً با بدنه فلزی توپی برخورد کند صدای بسیار شدیدی ایجاد می‌شود زنجیر به سرعت دندانه می‌خورد و پاره می‌شود و دندانه خورشیدی نیز خورده میشود');
اگر زنجیر در یکی از بخش‌های مسیر خود صدا می‌دهد یا به سمت دیواره توپی برخورد می‌کند، یعنی تراز بودن  از بین رفته است.');
بررسی میزان شل بودن زنجیراگر زنجیر خیلی شل باشد: در هنگام حرکت، زنجیر روی دندانه‌های توپی پرش می‌کند  که باعث ضربه به موتور و شکستن دندانه‌ها می‌شود و اگر زنجیر خیلی سفت باشد: فشار غیرعادی به بلبرینگ‌های موتور و یاتاقان‌های توپی وارد می‌شود و باعث داغ شدن سریع آن‌ها می‌گردد.');
با استفاده از تف (در صورت مجاز بودن) یا ترجیحاً با یک ترمومتر لیزری، دمای کاسه بلبرینگ را چک کنید. دمای غیرعادی نشان‌دهنده اصطکاک زیاد یا نبود روان‌کاری است.');
با استفاده از تف (در صورت مجاز بودن) یا ترجیحاً با یک ترمومتر لیزری، دمای کاسه بلبرینگ را چک کنید. دمای غیرعادی نشان‌دهنده اصطکاک زیاد یا نبود روان‌کاری است.');
گوش دادن به صدای چرخش. هرگونه صدای «زوزه»  یا «تق‌تق»  نشان‌دهنده آسیب به رینگ‌های بلبرینگ یا عدم تراز شفت است.');
بررسی  که آیا لرزش دستگاه در حد نرمال است یا لرزش‌های ضربه‌ای شنیده می‌شود.');
اگر سیستم روغن‌کاری  دستی دارد، چک کنید که آیا نشتی از آب‌بند (Seal) کاسه بلبرینگ وجود دارد یا خیر');
